scan_table_check.script:
(function (engine) {

	if (x_snc_codesanity.IsCheckApplicableToRecord())
	{
		var strType = x_snc_devtools.GetStringValue(current.internal_type);
		if (strType.indexOf('script') != 0)
		{
			return;
		}

		if (current.read_only == true)
		{
			return;
		}

		var grACL = new GlideRecord('sys_security_acl');
		grACL.addQuery('name', '=', current.name + '.' + current.element);
		grACL.addQuery('active', '=', 'true');
		grACL.addQuery('operation', '=', 'write');
		grACL.addQuery('decision_type', '=', 'deny');
		grACL.query();
		if (grACL.getRowCount() < 1)
		{
			engine.finding.increment();
			return;
		}

		var grRoleAdmin = x_snc_devtools.GetRoleRecord('admin');
		if (x_snc_devtools.IsValidRecord(grRoleAdmin) == false)
		{
			return;
		}

		var bAdminRoleFound = false;
		while (grACL.next())
		{
			var grAclRole = new GlideRecord('sys_security_acl_role');
			grAclRole.addQuery('sys_security_acl','=',grACL.sys_id);
			grAclRole.addQuery('sys_user_role', '=', grRoleAdmin.sys_id);
			grAclRole.query();
			if (grAclRole.getRowCount() > 0)
			{
				bAdminRoleFound = true;
			}
		}

		if (bAdminRoleFound == false)
		{
			engine.finding.increment();
		}
	}

})(engine);
